     5→//! Steeplechase Operations - git history parsing for JJ session tracking
     6→//!
     7→//! Implements jjx_rein: parse git history for steeplechase entries belonging to a Heat.
     8→//! Steeplechase entries are stored in git commit messages, not the Gallops JSON.
     9→//!
    10→//! New commit format: `jjb:BRAND:IDENTITY[:ACTION]: message`
    11→//! - IDENTITY: ₢CORONET for pace-level, ₣FIREMARK for heat-level
    12→//! - ACTION: Single letter code (optional for standard notch)
    13→
    14→use serde::Serialize;
    15→use std::process::Command;
    16→
    17→use crate::jjrf_favor::{jjrf_Firemark as Firemark, JJRF_FIREMARK_PREFIX as FIREMARK_PREFIX, JJRF_CORONET_PREFIX as CORONET_PREFIX};
    18→
    19→/// Arguments for jjx_rein command
    20→#[derive(Debug)]
    21→pub struct jjrs_ReinArgs {
    22→    /// Target Heat identity (Firemark, with or without prefix)
    23→    pub firemark: String,
    24→
    25→    /// Maximum entries to return
    26→    pub limit: usize,
    27→}
    28→
    29→/// Steeplechase entry - parsed from git commit message
    30→#[derive(Debug, Clone, Serialize)]
    31→pub struct jjrs_SteeplechaseEntry {
    32→    /// Timestamp in "YYYY-MM-DD HH:MM" format
    33→    pub timestamp: String,
    34→
    35→    /// Coronet for pace-level entries, None for heat-level
    36→    #[serde(skip_serializing_if = "Option::is_none")]
    37→    pub coronet: Option<String>,
    38→
    39→    /// Action code (single letter), 'n' for standard notch commits
    40→    #[serde(skip_serializing_if = "Option::is_none")]
    41→    pub action: Option<String>,
    42→
    43→    /// Commit message or marker description
    44→    pub subject: String,
    45→}
    46→
    47→/// Parse timestamp from git %ai format to "YYYY-MM-DD HH:MM"
    48→/// Input format: "2024-01-15 14:30:00 -0800"
    49→fn zjjrs_parse_timestamp(git_timestamp: &str) -> String {
    50→    let trimmed = git_timestamp.trim();
    51→    if trimmed.len() >= 16 {
    52→        trimmed[..16].to_string()
    53→    } else {
    54→        trimmed.to_string()
    55→    }
    56→}
    57→
    58→/// Parse a new-format commit: jjb:BRAND:IDENTITY[:ACTION]: message
    59→/// Filters by firemark identity, not by brand. Brand is parsed but not matched.
    60→fn zjjrs_parse_new_format(subject: &str, firemark_raw: &str) -> Option<jjrs_SteeplechaseEntry> {
    61→    // Expected format: jjb:BRAND:IDENTITY[:ACTION]: message
    62→    // We match any brand - filtering is by identity only
    63→    if !subject.starts_with("jjb:") {
    64→        return None;
    65→    }
    66→
    67→    // Skip past "jjb:" and find the brand (next colon-delimited segment)
    68→    let after_jjb = &subject[4..]; // skip "jjb:"
    69→    let brand_end = after_jjb.find(':')?;
    70→    let after_brand = &after_jjb[brand_end + 1..];
    71→
    72→    // Parse identity (₢CORONET or ₣FIREMARK)
    73→    let (identity, rest) = if after_brand.starts_with(CORONET_PREFIX) {
    74→        // Coronet: ₢XXXXX (1 prefix char + 5 base64 chars = 6 chars total in UTF-8)
    75→        let coronet_end = CORONET_PREFIX.len_utf8() + 5;
    76→        if after_brand.len() < coronet_end {
    77→            return None;
    78→        }
    79→        let coronet = &after_brand[..coronet_end];
    80→        // Verify this coronet belongs to our heat (first 2 chars of base64 match firemark)
    81→        let coronet_heat = &after_brand[CORONET_PREFIX.len_utf8()..CORONET_PREFIX.len_utf8() + 2];
    82→        if coronet_heat != firemark_raw {
    83→            return None;
    84→        }
    85→        (Some(coronet.to_string()), &after_brand[coronet_end..])
    86→    } else if after_brand.starts_with(FIREMARK_PREFIX) {
    87→        // Firemark: ₣XX (1 prefix char + 2 base64 chars)
    88→        let firemark_end = FIREMARK_PREFIX.len_utf8() + 2;
    89→        if after_brand.len() < firemark_end {
    90→            return None;
    91→        }
    92→        // Verify this is our firemark
    93→        let fm = &after_brand[FIREMARK_PREFIX.len_utf8()..firemark_end];
    94→        if fm != firemark_raw {
    95→            return None;
    96→        }
    97→        (None, &after_brand[firemark_end..])
    98→    } else {
    99→        return None;
   100→    };
   101→
   102→    // Now parse: [:ACTION]: message
   103→    // rest should start with either ": " (no action) or ":X: " (with action)
   104→    if !rest.starts_with(':') {
   105→        return None;
   106→    }
   107→
   108→    let after_colon = &rest[1..];
   109→
   110→    let (action, message) = if after_colon.starts_with(' ') {
   111→        // No action code, just ": message"
   112→        (None, after_colon[1..].to_string())
   113→    } else {
   114→        // Has action code: "X: message"
   115→        // Find the next colon
   116→        if let Some(colon_pos) = after_colon.find(':') {
   117→            let action_code = &after_colon[..colon_pos];
   118→            let msg = after_colon[colon_pos + 1..].trim_start().to_string();
   119→            (Some(action_code.to_string()), msg)
   120→        } else {
   121→            return None;
   122→        }
   123→    };
   124→
   125→    Some(jjrs_SteeplechaseEntry {
   126→        timestamp: String::new(), // filled by caller
   127→        coronet: identity,
   128→        action,
   129→        subject: message,
   130→    })
   131→}
   132→
   133→/// Parse a single git log line into a SteeplechaseEntry
   134→/// Line format: "YYYY-MM-DD HH:MM:SS -ZZZZ<TAB>subject"
   135→fn zjjrs_parse_log_line(line: &str, firemark_raw: &str) -> Option<jjrs_SteeplechaseEntry> {
   136→    let parts: Vec<&str> = line.splitn(2, '\t').collect();
   137→    if parts.len() != 2 {
   138→        return None;
   139→    }
   140→
   141→    let timestamp = zjjrs_parse_timestamp(parts[0]);
   142→    let subject = parts[1];
   143→
   144→    // Try parsing new format
   145→    if let Some(mut entry) = zjjrs_parse_new_format(subject, firemark_raw) {
   146→        entry.timestamp = timestamp;
   147→        return Some(entry);
   148→    }
   149→
   150→    None
   151→}
   152→
   153→/// Get steeplechase entries for a heat (library function)
   154→pub fn jjrs_get_entries(args: &jjrs_ReinArgs) -> Result<Vec<jjrs_SteeplechaseEntry>, String> {
   155→    let firemark = Firemark::jjrf_parse(&args.firemark)
   156→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   157→
   158→    let firemark_raw = firemark.jjrf_as_str();
   159→
   160→    // Build the grep pattern for git log
   161→    // Pattern matches both heat-level (₣XX) and pace-level (₢XX...) entries
   162→    // Filter by identity, not brand: jjb:*:₣XX or jjb:*:₢XX
   163→    let grep_pattern = format!(
   164→        "^jjb:[^:]+:({}{}|{}{})",
   165→        FIREMARK_PREFIX, firemark_raw,
   166→        CORONET_PREFIX, firemark_raw
   167→    );
   168→
   169→    let output = Command::new("git")
   170→        .args([
   171→            "log",
   172→            "--all",
   173→            "--extended-regexp",
   174→            &format!("--grep={}", grep_pattern),
   175→            "--format=%ai\t%s",
   176→        ])
   177→        .output()
   178→        .map_err(|e| format!("Failed to run git log: {}", e))?;
   179→
   180→    if !output.status.success() {
   181→        let stderr = String::from_utf8_lossy(&output.stderr);
   182→        return Err(format!("git log failed: {}", stderr));
   183→    }
   184→
   185→    let stdout = String::from_utf8_lossy(&output.stdout);
   186→
   187→    let entries: Vec<jjrs_SteeplechaseEntry> = stdout
   188→        .lines()
   189→        .filter_map(|line| zjjrs_parse_log_line(line, firemark_raw))
   190→        .take(args.limit)
   191→        .collect();
   192→
   193→    Ok(entries)
   194→}
   195→
   196→/// Run jjx_rein command (CLI wrapper)
   197→pub fn jjrs_run(args: jjrs_ReinArgs) -> i32 {
   198→    match jjrs_get_entries(&args) {
   199→        Ok(entries) => {
   200→            match serde_json::to_string_pretty(&entries) {
   201→                Ok(json) => {
   202→                    println!("{}", json);
   203→                    0
   204→                }
   205→                Err(e) => {
   206→                    eprintln!("rein: error: failed to serialize JSON: {}", e);
   207→                    1
   208→                }
   209→            }
   210→        }
   211→        Err(e) => {
   212→            eprintln!("rein: error: {}", e);
   213→            1
   214→        }
   215→    }
   216→}
